package com.example.data

data class DailyContent(
    val day: Int,
    val challenge: String,
    val tip: String
)

object Daily90Data {
    fun getDailyContent(day: Int, isAthlete: Boolean): DailyContent {
        val normalizedDay = if (day < 1) 1 else if (day > 90) 90 else day

        val challenge = when (normalizedDay) {
            1 -> "أوقف تشغيل هاتفك قبل النوم بـ 60 دقيقة وضعه خارج الغرفة تماماً 📱🔇"
            2 -> "ممارسة 15 تمرين ضغط فور الاستيقاظ لتنشيط دورتك الدموية وتدفق الأكسجين 🏋️‍♂️"
            3 -> "شرب 3 لترات من الماء اليوم وتجنب الجلوس بمفردك خلف باب مغلق 🚪💧"
            4 -> "المشي السريع لمدة 20 دقيقة في الهواء الطلق دون النظر لشاشة هاتفك 🚶‍♂️🌲"
            5 -> "كتابة 3 أهداف حقيقية تسعى لتحقيقها هذا الأسبوع على ورقة حقيقية وقراءتها 📝🎯"
            6 -> "الاستماع لبودكاست تحفيزي أو علمي لمدة 15 دقيقة أثناء القيام بتمارين تمدد 🎧🧠"
            7 -> "أخذ حمام بارد بالكامل (أو دقيقة باردة في نهاية استحمامك) لصعق رغبات الكسل 🥶🚿"
