        val tip = when (normalizedDay) {
            1 -> "البداية هي الأصعب دائماً. رغبتك اليوم طبيعية كصدمة انسحابية، قاومها بالصلاة والتنفس والابتعاد عن العزلة بالهاتف."
            2 -> "تذكر دائماً أن العقل سيبدأ في تبرير 'مرة واحدة فقط ولن تضر'. ذكّر نفسك بقوة أنك تبني كيمياء عصبية جديدة اليوم!"
            3 -> "الباب المفتوح والتواجد وسط العائلة هو أقوى درع حماية لك في البداية. تجنب البقاء وحيداً عندما تشعر بالملل."
            4 -> "الأكسجين النقي أثناء المشي يغذي قشرة الدماغ الجبهية (Prefrontal Cortex)، المسؤولة عن اتخاذ القرارات والتحكم بالإرادة."
            5 -> "عندما تهاجمك فكرة سلبية، لا تتجادل معها بل راقبها كغيمة تمر فوقك دون التفاعل معها. الرغبة تستمر دقائق فقط وتزول."
            6 -> "الفراغ الذهني هو ممر التسلل الأكبر للرغبات. املأ وقتك دوماً بالتعلم، القراءة، أو ممارسة الرياضة الحقيقية."
            7 -> "أسبوع كامل من الصمود يعيد ضبط كيمياء الدماغ ومستقبلات الدوبامين بنسبة ممتازة. فخورون بك جداً يا كابتن!"
            8 -> "دماغك يبحث عن التحفيز البصري السريع، درب عقلك على التركيز الهادئ والعميق من خلال القراءة والتدوين الورقي."
            9 -> "الفوضى البصرية في غرفتك تثير رغبة الهروب والكسل في عقلك. الترتيب الخارجي يمنح عقلك شعوراً رائعاً بالسيطرة والهدوء."
            10 -> "مقاومة التعب في تمارين بلانك تبني نفس المسارات العصبية التي تقاوم بها رغبة العادات السلبية. قوة الإرادة تتدرب كالعضلة!"
            11 -> "كل إشعار من هاتفك يسبب إفراز دوبامين مؤقت يتبعه رغبة في التصفح اللاواعي. التحكم في هاتفك هو أولى خطوات التحكم بحياتك."
            12 -> "التعافي الحقيقي ينمو بالاتصال الإنساني الحقيقي. العزلة تجذب الأفكار القديمة، فكن دائماً متصلاً بأشخاص إيجابيين."
            13 -> "تنظيم مستويات السكر في دمك يمنع تقلب المزاج المفاجئ الذي يستغله عقلك لإقناعك بالانتكاس. تناول طعاماً طبيعياً متوازناً."
            14 -> "الأسبوع الثاني اكتمل! مستويات هرمون التستوستيرون لديك في أعلى معدلاتها الطبيعية الآن. وجه هذه الطاقة الجبارة فوراً نحو أوزان الجيم أو المذاكرة."
            15 -> "الامتنان والرضا يفرزان هرمون السيروتونين والدوبامين الطبيعي، مما يشعرك بالسلام الداخلي ويطرد مشاعر الكآبة والضيق المؤقتة."
            16 -> "الصيام الرقمي المنتظم يقلل مستويات هرمون التوتر (الكورتيزول) في جسدك، مما يمنح جهازك العصبي الراحة العميقة للتعافي."
            17 -> "تمارين القرفصاء تحرك العضلات الكبيرة وتصرف الدم المتراكم في الحوض إلى الأطراف، وهي تكتيك دفاعي سريع لسحق الرغبات المفاجئة."
            18 -> "صفاء ذهنك اليوم يتيح لك الاستيعاب السريع والدراسة بتركيز مذهل. ضباب الدماغ يتلاشى الآن ليحل محله الفهم الحاد."
            19 -> "تصفح الهاتف فور الاستيقاظ يبرمج دماغك طوال اليوم للبحث عن التحفيز الرخيص والسهل. ابدأ يومك بهدوء ورياضة أو قراءة."
            20 -> "التغذية الصحية النظيفة والبروتين يمدان دماغك بالأحماض الأمينية اللازمة لبناء مستقبلات عصبية نقية واستعادة الحيوية الجسدية."
            21 -> "لقد اجتزت 21 يوماً كاملة! هذه هي المدة الكافية لتأسيس مسار عصبي جديد تماماً في دماغك وتطهير الجسم من العادة القديمة."
            22 -> "النشاط العملي واليدوي يفرز دوبامين الإنجاز الهادئ والراقي، وهو البديل الطبيعي الصحي الذي يغنيك عن المنبهات الرقمية الضارة."
            23 -> "التنفس المربع يهدئ الجهاز العصبي السمبتاوي فوراً ويقلل نبضات القلب السريعة، مما يسحق الرغبة المفاجئة في أقل من دقيقتين."
            24 -> "النوم المبكر والجودة العميقة للنوم هما المفتاح الأساسي لإفراز هرمون النمو وترميم الخلايا العصبية والجسدية المستنزفة."
            25 -> "العطاء ومساعدة الآخرين يمنحانك شعوراً بالتقدير الذاتي والقيمة الحقيقية في الحياة، مما يدعم ثقتك بنفسك ويزيل الكآبة."
            26 -> "الشكوى المستمرة تبرمج العقل على لعب دور الضحية العاجزة. تذكر أنك بطل صامد وقائد لمعركتك الشخصية، والحل في يدك دائماً."
            27 -> "الجهد البدني الشاق والوصول للتعب التام في التمرين يفرزان الإندورفين الذي يسكن الآلام ويمنحك نوماً عميقاً ومثاليّاً."
            28 -> "التخلص من الفوضى والملابس القديمة يعطي إشارة لاواعية لعقلك بأنك تتخلص من ماضيك السلبي وتستقبل مرحلة جديدة ومنظمة."
            29 -> "تفريغ الأفكار والمخاوف كتابةً يفرغ الشحنة العاطفية المحتبسة في اللوزة الدماغية (Amygdala) مما يزيل التوتر فوراً."
            30 -> "30 يوماً من الاستقامة والالتزام الكامل! مستقبلات المتعة لديك الآن تعمل بكفاءة أكبر بكثير، وبدأت تتذوق متعة الأشياء البسيطة."
            31 -> "قصص التغلب على الصعاب تثبت لك أن المعاناة مؤقتة وأن المجد الحقيقي يولد من رحم الصبر والثبات على المبادئ."
            32 -> "الكافيين المتأخر يزيد الأرق والتوتر العصبي ليلاً، مما يجعلك عرضة لضعف الإرادة تحت وطأة التعب والملل. نم هادئاً."
            33 -> "الاندماج مع الطبيعة يقلل من نشاط منطقة الدماغ المسؤولة عن القلق والتفكير السلبي المتكرر، ويمنحك صفاءً وراحة بصرية لا تقارن."
            34 -> "تحدي عقلك بحفظ أشياء جديدة يبني مرونة عصبية مذهلة ويقوي الذاكرة قصيرة وطويلة المدى التي دمرتها الممارسات القديمة."
            35 -> "الفوضى الرقمية والملفات الكثيرة غير المنظمة تسبب تشتتاً لاواعياً. رتب بيئتك الرقمية لتصبح بيئة تعافي نظيفة ومحفزة."
            36 -> "عندما تشعر بالكسل والخمول، تذكر أن الحركة تولد الحركة والنشاط. ابدأ بالقيام بتمارين خفيفة وسيتكفل جسدك بالباقي."
            37 -> "الصيام الرقمي يعيد لعقلك التوازن ويحميك من قصف الدوبامين المستمر الناتج عن تصفح المقاطع السريعة بلا هدف."
            38 -> "التأمل في المنجزات السابقة وبناء الوعي الذاتي يمنعك من التقليل من شأن تقدمك ويحميك من فخ الاستسلام المؤقت."
            39 -> "الجلوس الطويل والخمول الجسدي يتسببان في ركود دورتك الدموية وزيادة الوساوس. قف وتحرك واجعل طاقتك دائماً في سريان."
            40 -> "تعلم مهارة حركية أو رياضة جديدة يحفز المخيخ ويبني روابط عصبية جديدة كلياً تسرع من شفاء وتطور الدماغ."
            41 -> "كل عادة سلبية تترك فراغاً، والسر في التخلص منها هو إحلال عادة إيجابية مكانها تملأ هذا الفراغ وتشغل وقتك وعقلك."
            42 -> "مشاركة الإيجابية تزيد من التزامك الشخصي بها. عندما تدعو الآخرين للتعافي والصمود، فإنك تثبت هذا المبدأ في عقلك أولاً."
            43 -> "الدهون الصحية والمعادن كالزنك ضرورية جداً لاستشفاء الخلايا وتصنيع الهرمونات الطبيعية وتحسين الأداء العصبي والعضلي."
            44 -> "ترتيب وتنظيم الملفات يمنحك شعوراً بالإنجاز السريع والمسيطر، مما يفرز دوبامين طبيعياً يعزز رغبتك في الاستمرار بالتعافي."
            45 -> "الوصول لمنتصف الطريق (45 يوماً) يعني أن أصعب العقبات باتت خلفك. دماغك الآن في قمة التعافي العصبى والتركيز الذهني مستقر."
            46 -> "توجيه ذهنك نحو بناء المستقبل والمشاريع يسحب تركيزك بالكامل من الماضي السلبي ويجعلك تعيش بدافع الشغف والبناء."
            47 -> "الفيديوهات القصيرة تدمر مدى انتباهك وتجعلك تمل بسرعة من المهام الطويلة كالمذاكرة والرياضة. تخلص منها لتستعيد عقلك الحاد."
            48 -> "الاهتمام بالمظهر والنظافة الشخصية يرفع من هرمونات السعادة والثقة بالنفس، ويجعلك تشعر بأنك شخص جديد يستحق الأفضل دائماً."
            49 -> "الهدوء والصمت والجلوس دون مدخلات بصرية يعيد شحن طاقة قشرة الدماغ ويرفع مستويات الوعي والتحكم الذاتي لديك."
            50 -> "50 يوماً من العظمة والحرية! أنت الآن تصنع قدوة حقيقية لمن حولك. ثقتك بنفسك وهيبتك وصوتك ومظهرك كلها تغيرت للأفضل!"
            51 -> "التعلم المستمر هو غذاء العقل النامي. كل صفحة تقرؤها تبني حصناً من الوعي يحميك من الانزلاق في مستنقعات الإدمان القديمة."
            52 -> "تقوية عضلات الجذع تحسن من وضعية جسدك وتنفسك، وتمنع آلام الظهر، مما ينعكس إيجابياً على حالتك النفسية والبدنية العامة."
            53 -> "الوجبات السريعة غنية بالسموم والدهون المهدرجة التي تسبب التهابات خفيفة في الجسم والدماغ، مما يضعف المناعة والقدرة الذهنية."
            54 -> "مساعدة الأهل بروح طيبة تنمي فيك خصلة المسؤولية والرجولة، وتشعرك بالرضا الداخلي والبركة العظيمة في وقتك وجهدك."
            55 -> "الاسترخاء العضلي المتدرج يزيل التشنجات العضلية المتراكمة طوال اليوم ويهيئ جهازك العصبي لنوم عميق ومريح للغاية."
            56 -> "الاعتراف بفضل من علمونا يطهر النفس من الكبر والغرور، ويملأ قلبك بمشاعر التقدير والامتنان البناءة للتعافي والنمو الشخصي."
            57 -> "جدولة مهامك بدقة تحميك من العشوائية. العشوائية والملل هما البيئة الخصبة لظهور الوساوس ورغبات التراجع السلبية."
            58 -> "تدريب الأرجل يحفز إفراز التستوستيرون وهرمون النمو بشكل طبيعي وجبار، مما يساعد في استشفاء كامل عضلات الجسم وأجهزته."
            59 -> "الكلمات الطيبة والبناءة تؤثر إيجابياً على عقلك الباطن وتزيد من ثقتك بقدرتك على تجاوز الصعاب. الكلمات تصنع الواقع!"
            60 -> "ستون يوماً من الاستقامة! تذكر أنك تخلصت من قيود العبودية الرقمية، واستعدت حريتك وسيادتك. واصل المسير يا بطل."
            61 -> "التخطيط المسبق يمنح عقلك خارطة طريق واضحة ويقلل من القلق وتشتت القرارات اليومية، مما يوفر طاقتك الذهنية للصمود والعمل."
            62 -> "التلامس مع الأرض يفرغ الشحنات الكهرومغناطيسية الزائدة من جسدك ويقلل الالتهابات ويزيد من شعورك بالراحة والاتصال بالطبيعة."
            63 -> "تناول الطعام بوعي ودون هواتف يحسن الهضم والامتصاص ويمنع الإفراط في الأكل، ويدرب عقلك على الاستمتاع باللحظة الحاضرة."
            64 -> "التمارين المتناوبة تنشط الدورة الدموية الكبرى وتزيد السعة الرئوية، مما يمد عضلاتك وعقلك بدفقات هائلة من الأكسجين والطاقة."
            65 -> "الهدوء السائد قبل الفجر هو أفضل وقت للتأمل والدعاء والتواصل الروحي، مما يمنحك سلاماً داخلياً وطاقة روحية تسحق الصعاب."
            66 -> "التلدن العصبي (Neuroplasticity) يؤكد أن الدماغ يستطيع إصلاح نفسه تماماً وبناء مسارات عصبية بديلة وصحية مئة بالمئة."
            67 -> "العمل الطيب والتصدق يطهران الروح من الأنانية ويبثان مشاعر السلام والرضا العميقة التي تعزز مناعتك النفسية والجسدية."
            68 -> "تطهير مستقبلات الأدينوسين يعيد لجسمك القدرة على النوم الطبيعي العميق دون الحاجة لمنبهات، لتستيقظ بكامل النشاط والحيوية."
            69 -> "الكتب الصوتية هي الطريقة المثلى لاستغلال الأوقات البينية (المشي، التنظيف) لملء عقلك بالأفكار البناءة والعلوم النافعة."
            70 -> "التمارين عالية الكثافة تقوي عضلة القلب وتزيد من إنتاج الإندورفين الذي يسكن الآلام ويطرد التوتر والقلق العصبي بكفاءة."
            71 -> "لا وجود للفشل، بل هناك دروس مستفادة فقط. تعثراتك القديمة كانت ضرورية لتعرف نقاط ضعفك وتغلقها وتصبح اليوم حديدياً صامداً."
            72 -> "وضعية الجسد المستقيمة ترسل إشارات هرمونية فورية للدماغ لزيادة إفراز التستوستيرون وتقليل الكورتيزول، مما يرفع ثقتك بنفسك."
            73 -> "الانفصال التام عن الهاتف لبضع ساعات يومياً يمنح عقلك فرصة للتفكير الإبداعي وحل المشكلات والتركيز العميق في العمل والدراسة."
            74 -> "البابونج والمشروبات الدافئة تحفز النواقل العصبية المهدئة مثل GABA، مما يقلل من نشاط الدماغ الزائد ويهيئه للنوم المثالي."
            75 -> "تجاوز الـ 75 يوماً يثبت أنك أصبحت سيداً على رغباتك وعقلك. لم تعد العادات القديمة تسيطر عليك، بل أنت من يوجه طاقتك."
            76 -> "التعبير عن التقدير والامتنان للآخرين يقوي الروابط الاجتماعية والصداقات، وهي الركيزة الأساسية لحياة صحية ومتزنة بعد التعافي."
            77 -> "الأخبار السلبية المستمرة تضع دماغك في حالة دفاع وقلق دائم (Fight or Flight) مما يستنزف طاقتك الذهنية ويعرضك للانتكاس."
            78 -> "تمارين الضغط اليومية تبني عضلات الصدر والأكتاف والساعدين وتمنحك قواماً رياضياً مهيباً يزيد من ثقتك بنفسك وقوتك الجسدية."
            79 -> "التركيز الطويل في كتاب علمي معقد يعيد بناء خلايا الانتباه والتركيز التي دمرها التصفح السريع والمثيرات البصرية المتكررة."
            80 -> "التخلص من الملفات والمقتنيات القديمة يعطي إشارة للدماغ بالتحرر الكامل من الماضي وفتح صفحة جديدة ومشرقة في الحياة."
            81 -> "التنفس البطيء والعميق في الصباح يؤكسج الدم ويهيئ جهازك العصبي ليوم مليء بالتركيز والإنتاجية والسلام الداخلي."
            82 -> "تناول الطعام ببطء ووعي يزيد من إفراز هرمونات الشبع والرضا، ويدرب العقل على الصبر والاستمتاع بالنعم البسيطة."
            83 -> "المشي في الهواء الطلق يزيد من مستويات فيتامين د ويحسن المزاج ويطرد مشاعر الاكتئاب والملل بشكل طبيعي وفوري."
            84 -> "التحرر من شاشات الهواتف يتيح لك رؤية جمال الحياة الحقيقية والتفاعل مع الواقع بوعي وحضور كاملين دون مشتتات."
            85 -> "تمارين تمدد الرقبة والظهر تخلصك من الشد العضلي الناتج عن الجلوس الطويل وتسمح بتدفق الدم والأكسجين للدماغ بسلاسة."
            86 -> "التخطيط للمستقبل يمنحك دافعاً وشغفاً حقيقياً للاستيقاظ كل صباح والعمل بجد واجتهاد لتحقيق ذاتك وأهدافك الكبرى."
            87 -> "صنع المعروف سراً يبني روحاً نقية ومتواضعة، ويشعرك ببركة إلهية وراحة نفسية عميقة تعينك على الصمود والاستقامة."
            88 -> "ممارسة تمارين رياضية شاقة تفرغ أي طاقة محبوسة أو توتر متراكم وتمنحك شعوراً بالانتعاش والقوة والسيطرة البدنية الكاملة."
            89 -> "تأمل كيف بدأت وكيف أصبحت الآن. القوة التي بنيتها، والوعي الذي اكتسبته، والحرية التي تنعم بها الآن تستحق الحفاظ عليها للأبد."
            90 -> "تهانينا الحارة يا بطل الأبطال! لقد أتممت الـ 90 يوماً التاريخية واستعدت توازن دماغك وجسدك بالكامل. أنت الآن رجل حر ومستقيم!"
            else -> "استمر في روتين الصمود اليومي وتجنب المثيرات لتعزيز استقامتك مدى الحياة 🌟"
        }

        val finalTip = if (isAthlete) {
            tip + " (بصفتك رياضياً، عضلاتك وتستوستيرونك الآن في أفضل حالاتهم للنمو البدني!)"
        } else {
            tip + " (بصفتك طالباً وباحثاً، قدرتك الدراسية وذكاؤك الآن في قمة توهجهما الأكاديمي!)"
        }

        return DailyContent(
            day = normalizedDay,
            challenge = challenge,
            tip = finalTip
        )
    }
}
